/// Returns the symbols for a given index name (case-insensitive).
pub fn get_index_symbols(name: &str) -> Option<Vec<String>> {
    let upper = name.to_uppercase();
    match upper.as_str() {
        "SP500" | "S&P 500" => Some(SP500.iter().map(|s| s.to_string()).collect()),
        "NASDAQ100" | "NASDAQ 100" => Some(NASDAQ100.iter().map(|s| s.to_string()).collect()),
        "DJIA" | "Dow Jones 30" => Some(DJIA.iter().map(|s| s.to_string()).collect()),
        "FTSE100" | "FTSE 100" => Some(FTSE100.iter().map(|s| s.to_string()).collect()),
        "DAX40" | "DAX 40" => Some(DAX40.iter().map(|s| s.to_string()).collect()),
        "CAC40" | "CAC 40" => Some(CAC40.iter().map(|s| s.to_string()).collect()),
        "EUROSTOXX50" | "Euro Stoxx 50" => Some(EUROSTOXX50.iter().map(|s| s.to_string()).collect()),
        "NIKKEI225" | "Nikkei 225" => Some(NIKKEI225.iter().map(|s| s.to_string()).collect()),
        "HANGSENG" | "Hang Seng" => Some(HANGSENG.iter().map(|s| s.to_string()).collect()),
        "SSE100" | "SSE Composite Top 100" => Some(SSE100.iter().map(|s| s.to_string()).collect()),
        "KOSPI80" | "KOSPI Top 80" => Some(KOSPI80.iter().map(|s| s.to_string()).collect()),
        "TWSE50" | "TWSE/TAIEX Top 50" => Some(TWSE50.iter().map(|s| s.to_string()).collect()),
        "TSX60" | "TSX 60" => Some(TSX60.iter().map(|s| s.to_string()).collect()),
        "BOVESPA50" | "Bovespa Top 50" => Some(BOVESPA50.iter().map(|s| s.to_string()).collect()),
        "IPCMEXICO30" | "IPC Mexico Top 30" => Some(IPCMEXICO30.iter().map(|s| s.to_string()).collect()),
        "TADAWUL50" | "Tadawul Top 50" => Some(TADAWUL50.iter().map(|s| s.to_string()).collect()),
        "BIST100" | "BIST 100" => Some(BIST100.iter().map(|s| s.to_string()).collect()),
        "ASX200" | "ASX 200" => Some(ASX200.iter().map(|s| s.to_string()).collect()),
        "GLOBAL_ETFS" | "Global ETFs" => Some(GLOBAL_ETFS.iter().map(|s| s.to_string()).collect()),
        _ => None,
    }
}

